input.command:
agent-browser execute "() => {
  const elements = Array.from(document.querySelectorAll('text'));
  const adelie = elements.find(e => e.textContent === 'Adelie');
  if (!adelie) return 'Adelie not found';
  const style = window.getComputedStyle(adelie);
  return {
    textContent: adelie.textContent,
    cursor: style.cursor,
    tagName: adelie.tagName
  };
}"

agent-browser execute "() => {
  const el = Array.from(document.querySelectorAll('*')).find(e => e.textContent === 'Adelie');
  return el ? window.getComputedStyle(el).cursor : 'not found';
}"
